using Contoso.Pricing;

namespace Contoso.Pricing.Tests;

[TestClass]
public sealed class PriceCalculatorTests
{
    private PriceCalculator _calculator = null!;

    [TestInitialize]
    public void Setup() => _calculator = new PriceCalculator();

    // ───────────────────────────────────────────────
    //  CalculateTotal – DataRow tests
    // ───────────────────────────────────────────────

    [TestMethod]
    [DataRow(10.00, 1, 0.0,  10.00,  DisplayName = "Single item, no tax")]
    [DataRow(10.00, 5, 0.0,  50.00,  DisplayName = "Multiple items, no tax")]
    [DataRow(10.00, 1, 0.10, 11.00,  DisplayName = "Single item, 10% tax")]
    [DataRow(25.50, 3, 0.08, 82.62,  DisplayName = "Fractional price, 8% tax")]
    [DataRow(0.00,  5, 0.10, 0.00,   DisplayName = "Zero unit price")]
    [DataRow(10.00, 0, 0.10, 0.00,   DisplayName = "Zero quantity")]
    [DataRow(99.99, 1, 1.0,  199.98, DisplayName = "Maximum tax rate (100%)")]
    public void CalculateTotal_WithValidInputs_ReturnsExpectedTotal(
        double unitPrice, int quantity, double taxRate, double expectedTotal)
    {
        var result = _calculator.CalculateTotal((decimal)unitPrice, quantity, (decimal)taxRate);

        Assert.AreEqual((decimal)expectedTotal, result);
    }

    // ───────────────────────────────────────────────
    //  CalculateTotal – DynamicData (edge / error cases)
    // ───────────────────────────────────────────────

    public static IEnumerable<object[]> InvalidCalculateTotalInputs =>
    [
        [/* unitPrice */ -1m,  /* qty */ 1,  /* tax */ 0.1m, typeof(ArgumentOutOfRangeException), "Negative unit price"],
        [/* unitPrice */  1m,  /* qty */ -1, /* tax */ 0.1m, typeof(ArgumentOutOfRangeException), "Negative quantity"],
        [/* unitPrice */  1m,  /* qty */ 1,  /* tax */ -0.1m, typeof(ArgumentOutOfRangeException), "Negative tax rate"],
        [/* unitPrice */  1m,  /* qty */ 1,  /* tax */ 1.1m,  typeof(ArgumentOutOfRangeException), "Tax rate above 1"],
    ];

    [TestMethod]
    [DynamicData(nameof(InvalidCalculateTotalInputs), DynamicDataDisplayName = nameof(GetDisplayName))]
    public void CalculateTotal_WithInvalidInputs_Throws(
        decimal unitPrice, int quantity, decimal taxRate, Type expectedException, string scenario)
    {
        Assert.ThrowsExactly(
            expectedException,
            () => _calculator.CalculateTotal(unitPrice, quantity, taxRate),
            $"Expected {expectedException.Name} for scenario: {scenario}");
    }

    // ───────────────────────────────────────────────
    //  ApplyDiscount – DataRow tests
    // ───────────────────────────────────────────────

    [TestMethod]
    [DataRow(100.00, 0.0,   100.00, DisplayName = "No discount")]
    [DataRow(100.00, 10.0,  90.00,  DisplayName = "10% discount")]
    [DataRow(100.00, 50.0,  50.00,  DisplayName = "50% discount")]
    [DataRow(100.00, 100.0, 0.00,   DisplayName = "100% discount (free)")]
    [DataRow(49.99,  25.0,  37.4925, DisplayName = "Fractional result")]
    [DataRow(0.00,   50.0,  0.00,   DisplayName = "Zero price with discount")]
    public void ApplyDiscount_WithValidInputs_ReturnsExpectedPrice(
        double price, double discountPercent, double expectedPrice)
    {
        var result = _calculator.ApplyDiscount((decimal)price, (decimal)discountPercent);

        Assert.AreEqual((decimal)expectedPrice, result);
    }

    // ───────────────────────────────────────────────
    //  ApplyDiscount – DynamicData (boundary errors)
    // ───────────────────────────────────────────────

    public static IEnumerable<object[]> InvalidDiscountInputs =>
    [
        [100m, -1m,  "Negative discount"],
        [100m, 101m, "Discount above 100%"],
    ];

    [TestMethod]
    [DynamicData(nameof(InvalidDiscountInputs), DynamicDataDisplayName = nameof(GetDisplayName))]
    public void ApplyDiscount_WithInvalidDiscount_ThrowsArgumentOutOfRange(
        decimal price, decimal discountPercent, string scenario)
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.ApplyDiscount(price, discountPercent),
            $"Expected exception for scenario: {scenario}");
    }

    // ───────────────────────────────────────────────
    //  Shared display-name resolver for DynamicData
    // ───────────────────────────────────────────────

    public static string GetDisplayName(MethodInfo methodInfo, object?[] data) =>
        $"{methodInfo.Name} ({data[^1]})";
}

